from collections import OrderedDict

class LRUCache:
    def __init__(self, capacity: int):
        self.capacity = capacity
        self._cache: OrderedDict = OrderedDict()

    def get(self, key):
        if key not in self._cache:
            return None
        self._cache.move_to_end(key)  # Mark as recently used
        return self._cache[key]

    def put(self, key, value):
        if key in self._cache:
            self._cache.move_to_end(key)
        self._cache[key] = value
        if len(self._cache) > self.capacity:
            self._cache.popitem(last=False)  # Remove least recently used

    def __len__(self):
        return len(self._cache)

    def __contains__(self, key):
        return key in self._cache

# Usage
cache = LRUCache(3)
cache.put('a', 1)
cache.put('b', 2)
cache.put('c', 3)
cache.get('a')      # Returns 1, 'a' is now most recent
cache.put('d', 4)   # Evicts 'b' (least recently used)
print('b' in cache) # False
```

OrderedDict maintains insertion order. `move_to_end()` marks access. `popitem(last=False)` removes the oldest entry. All operations are O(1). This is the same algorithm used by CPU caches and database buffer pools.

