from collections import defaultdict
from typing import Callable

class EventBus:
    def __init__(self):
        self._listeners: dict[str, list[Callable]] = defaultdict(list)

    def on(self, event: str, callback: Callable):
        self._listeners[event].append(callback)

    def off(self, event: str, callback: Callable):
        self._listeners[event] = [cb for cb in self._listeners[event] if cb != callback]

    def emit(self, event: str, **kwargs):
        for callback in self._listeners.get(event, []):
            callback(**kwargs)

# Usage
bus = EventBus()
def on_login(user_id: str): print(f'User {user_id} logged in')
bus.on('user.login', on_login)
bus.emit('user.login', user_id='u_123')
```

The Observer pattern decouples producers from consumers. The EventBus maps event names to callbacks. This is the foundation of plugin systems and notification architectures.

