import time, functools, logging
logger = logging.getLogger(__name__)

def retry(max_attempts=3, base_delay=1.0, exceptions=(Exception,)):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            for attempt in range(1, max_attempts + 1):
                try:
                    return func(*args, **kwargs)
                except exceptions as e:
                    if attempt == max_attempts:
                        logger.error(f'{func.__name__} failed after {max_attempts} attempts: {e}')
                        raise
                    delay = base_delay * (2 ** (attempt - 1))
                    logger.warning(f'{func.__name__} attempt {attempt} failed. Retrying in {delay}s...')
                    time.sleep(delay)
        return wrapper
    return decorator

@retry(max_attempts=3, base_delay=0.5, exceptions=(ConnectionError, TimeoutError))
def fetch_data(url): ...
```

Backoff: 0.5s, 1s, then raise. Preserves function name/docstring via `functools.wraps`.

