from abc import ABC, abstractmethod
from typing import Type
import importlib
import pkgutil

class Plugin(ABC):
    """Base class all plugins must inherit from."""
    _registry: dict[str, Type['Plugin']] = {}

    def __init_subclass__(cls, **kwargs):
        super().__init_subclass__(**kwargs)
        if not getattr(cls, '__abstractmethods__', None):
            Plugin._registry[cls.name] = cls

    @property
    @abstractmethod
    def name(self) -> str: ...

    @property
    @abstractmethod
    def version(self) -> str: ...

    @abstractmethod
    def execute(self, context: dict) -> dict: ...

    @classmethod
    def get_all(cls) -> dict[str, Type['Plugin']]:
        return dict(cls._registry)

    @classmethod
    def get(cls, name: str) -> Type['Plugin'] | None:
        return cls._registry.get(name)

# Example plugin (in a separate file)
class WeatherPlugin(Plugin):
    name = 'weather'
    version = '1.0'
    def execute(self, context):
        return {'forecast': 'sunny', 'temp': 25}

class EmailPlugin(Plugin):
    name = 'email'
    version = '1.0'
    def execute(self, context):
        return {'sent': True, 'to': context.get('recipient')}

# Host application discovers and uses plugins
for name, plugin_cls in Plugin.get_all().items():
    plugin = plugin_cls()
    result = plugin.execute({'recipient': 'user@example.com'})
    print(f'{name} v{plugin.version}: {result}')
```

Plugins self-register via `__init_subclass__`. The host never needs to know about specific plugins — it discovers them at runtime. To load plugins from a directory, use `importlib` + `pkgutil` to import all modules from a `plugins/` folder.

