import time
from functools import wraps
from typing import Callable

def cache(ttl_seconds: int = 300):
    """Cache decorator with TTL. Results expire after ttl_seconds."""
    def decorator(func: Callable):
        _cache: dict = {}

        @wraps(func)
        def wrapper(*args, **kwargs):
            # Create a hashable cache key from arguments
            key = (args, tuple(sorted(kwargs.items())))

            # Check cache
            if key in _cache:
                result, timestamp = _cache[key]
                if time.time() - timestamp < ttl_seconds:
                    return result  # Cache hit
                del _cache[key]  # Expired

            # Cache miss — call function
            result = func(*args, **kwargs)
            _cache[key] = (result, time.time())
            return result

        def clear():
            _cache.clear()

        def stats():
            now = time.time()
            valid = sum(1 for _, (_, ts) in _cache.items()
                       if now - ts < ttl_seconds)
            return {'total': len(_cache), 'valid': valid, 'expired': len(_cache) - valid}

        wrapper.clear_cache = clear
        wrapper.cache_stats = stats
        return wrapper
    return decorator

# Usage
@cache(ttl_seconds=60)
def get_user(user_id: int) -> dict:
    print(f'DB query for user {user_id}')  # Only prints on cache miss
    return {'id': user_id, 'name': 'Alice'}

get_user(1)  # DB query (cache miss)
get_user(1)  # Returns cached (no DB query)
get_user(1)  # Returns cached (no DB query)

print(get_user.cache_stats())  # {'total': 1, 'valid': 1, 'expired': 0}
get_user.clear_cache()  # Reset
```

This is a simplified version of `functools.lru_cache` with TTL support. For production, use `cachetools.TTLCache` or Redis for distributed caching across multiple processes.

