from dataclasses import dataclass
import json
import re

@dataclass(frozen=True)
class SemVer:
    major: int
    minor: int
    patch: int
    prerelease: str = ''

    @classmethod
    def parse(cls, version: str) -> 'SemVer':
        match = re.match(r'^v?(\d+)\.(\d+)\.(\d+)(?:-(\S+))?$', version)
        if not match:
            raise ValueError(f'Invalid semver: {version}')
        return cls(
            int(match[1]), int(match[2]), int(match[3]),
            match[4] or ''
        )

    def __str__(self) -> str:
        base = f'{self.major}.{self.minor}.{self.patch}'
        return f'{base}-{self.prerelease}' if self.prerelease else base

    def __lt__(self, other: 'SemVer') -> bool:
        if (self.major, self.minor, self.patch) != (other.major, other.minor, other.patch):
            return (self.major, self.minor, self.patch) < (other.major, other.minor, other.patch)
        if self.prerelease and not other.prerelease:
            return True  # Pre-release < release
        return self.prerelease < other.prerelease

    def __le__(self, other): return self == other or self < other
    def __gt__(self, other): return other < self
    def __ge__(self, other): return self == other or self > other

    def to_dict(self) -> dict:
        return {'major': self.major, 'minor': self.minor,
                'patch': self.patch, 'prerelease': self.prerelease}

# Usage
versions = [SemVer.parse('2.1.0'), SemVer.parse('1.9.5'), SemVer.parse('2.1.0-beta')]
print(sorted(versions))  # [1.9.5, 2.1.0-beta, 2.1.0]
```

`frozen=True` makes it hashable (usable in sets/dicts). Custom `__lt__` enables sorting. Pre-release versions sort before their release counterpart per SemVer spec.

