**Structured error handling for a Flask/Python API:**

```python
from flask import Flask, jsonify, request
from werkzeug.exceptions import HTTPException
import logging
import traceback

app = Flask(__name__)
logger = logging.getLogger(__name__)

# Custom exception classes
class APIError(Exception):
    def __init__(self, message, status_code=400, error_code=None):
        self.message = message
        self.status_code = status_code
        self.error_code = error_code or 'BAD_REQUEST'

class NotFoundError(APIError):
    def __init__(self, resource, resource_id):
        super().__init__(
            f'{resource} with id {resource_id} not found',
            status_code=404,
            error_code='NOT_FOUND'
        )

class ValidationError(APIError):
    def __init__(self, errors: dict):
        super().__init__(
            'Validation failed',
            status_code=422,
            error_code='VALIDATION_ERROR'
        )
        self.errors = errors

# Global error handlers
@app.errorhandler(APIError)
def handle_api_error(e):
    response = {
        'error': e.error_code,
        'message': e.message,
    }
    if hasattr(e, 'errors'):
        response['details'] = e.errors
    return jsonify(response), e.status_code

@app.errorhandler(HTTPException)
def handle_http_error(e):
    return jsonify(error=e.name, message=e.description), e.code

@app.errorhandler(Exception)
def handle_unexpected_error(e):
    logger.exception('Unexpected error: %s', e)
    # Don't expose internal details in production
    return jsonify(
        error='INTERNAL_ERROR',
        message='An unexpected error occurred'
    ), 500

# Usage in routes
@app.route('/users/<int:user_id>')
def get_user(user_id):
    user = db.get_user(user_id)
    if not user:
        raise NotFoundError('User', user_id)
    return jsonify(user)

@app.route('/users', methods=['POST'])
def create_user():
    data = request.json
    errors = {}
    if not data.get('email'):
        errors['email'] = 'Email is required'
    if not data.get('name'):
        errors['name'] = 'Name is required'
    if errors:
        raise ValidationError(errors)
    user = db.create_user(data)
    return jsonify(user), 201
```

**Error response format (consistent for all errors):**
```json
{
  "error": "VALIDATION_ERROR",
  "message": "Validation failed",
  "details": {
    "email": "Email is required",
    "name": "Name is required"
  }
}
```

**Rules:**
- Always return JSON (never HTML error pages from an API)
- Use appropriate HTTP status codes (400, 401, 403, 404, 422, 500)
- Never expose stack traces in production
- Log all 500 errors with full traceback (server-side only)
- Include machine-readable error codes (for client-side handling)

**JWT authentication for Flask — complete implementation:**

```python
from flask import Flask, request, jsonify
from functools import wraps
import jwt
import datetime
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key-change-this'  # Use env var in production!

# Simulated user store (use a real database)
users = {}

def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization', '').replace('Bearer ', '')
        if not token:
            return jsonify(error='Token missing'), 401
        try:
            payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
            request.user_id = payload['user_id']
        except jwt.ExpiredSignatureError:
            return jsonify(error='Token expired'), 401
        except jwt.InvalidTokenError:
            return jsonify(error='Invalid token'), 401
        return f(*args, **kwargs)
    return decorated

@app.route('/register', methods=['POST'])
def register():
    data = request.json
    if data['email'] in users:
        return jsonify(error='User exists'), 409
    users[data['email']] = {
        'password': generate_password_hash(data['password']),
        'name': data['name']
    }
    return jsonify(message='Registered'), 201

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    user = users.get(data['email'])
    if not user or not check_password_hash(user['password'], data['password']):
        return jsonify(error='Invalid credentials'), 401
    token = jwt.encode({
        'user_id': data['email'],
        'exp': datetime.datetime.utcnow() + datetime.timedelta(hours=24)
    }, app.config['SECRET_KEY'], algorithm='HS256')
    return jsonify(token=token)

@app.route('/protected')
@token_required
def protected():
    return jsonify(message=f'Hello {request.user_id}')
```

**How it works:**
1. User registers with email + password (password is hashed)
2. User logs in → receives a JWT token (valid 24 hours)
3. User includes token in header: `Authorization: Bearer <token>`
4. `@token_required` decorator validates the token on protected routes

**Security checklist:**
- Store `SECRET_KEY` in environment variable, never in code
- Use `HS256` algorithm minimum; `RS256` (asymmetric) for distributed systems
- Set reasonable token expiry (1-24 hours)
- Implement refresh tokens for long sessions
- Hash passwords with `werkzeug.security` (uses pbkdf2 by default)
- Install: `pip install PyJWT flask`

