        return {'status': 'ok', 'latency_ms': round((time.monotonic()-start)*1000, 1)}
    except Exception as e:
        return {'status': 'error', 'error': str(e)}

def check_disk():
    usage = shutil.disk_usage('/')
    free_pct = (usage.free / usage.total) * 100
    return {'status': 'ok' if free_pct > 10 else 'warning', 'free_pct': round(free_pct, 1)}

@app.route('/health')
def health():
    checks = {'database': check_db(), 'redis': check_redis(), 'disk': check_disk()}
    ok = all(c['status'] == 'ok' for c in checks.values())
    return jsonify(status='healthy' if ok else 'degraded', checks=checks), 200 if ok else 503
```

Return 200 healthy / 503 degraded so load balancers route correctly. Include latency per dependency. Don't expose sensitive info.

