import json, time, redis
from datetime import datetime

class TaskQueue:
    def __init__(self, name='tasks', redis_url='redis://localhost:6379/0'):
        self.name = name
        self.redis = redis.from_url(redis_url)
        self._handlers = {}

    def register(self, task_type, handler):
        self._handlers[task_type] = handler

    def enqueue(self, task_type, payload):
        task = {'id': f'{task_type}_{int(time.time()*1000)}', 'type': task_type,
                'payload': payload, 'created_at': datetime.utcnow().isoformat()}
        self.redis.lpush(self.name, json.dumps(task))
        return task['id']

    def worker(self, timeout=5):
        while True:
            result = self.redis.brpop(self.name, timeout=timeout)
            if not result: continue
            task = json.loads(result[1])
            handler = self._handlers.get(task['type'])
            if handler:
                try:
                    handler(task['payload'])
                except Exception as e:
                    self.redis.lpush(f'{self.name}:failed', json.dumps(task))
```

Uses Redis LPUSH/BRPOP for FIFO with blocking. Failed tasks go to a dead-letter queue. For production use Celery or RQ.

