interface UserProfile {
  id: string; email: string; name: string;
  role: 'admin' | 'editor' | 'viewer'; created_at: string;
}

interface ValidationError { field: string; message: string; }

const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const ROLES = new Set(['admin', 'editor', 'viewer']);

function validateUserProfile(data: unknown): { valid: boolean; errors: ValidationError[] } {
  const errors: ValidationError[] = [];
  const d = data as Record<string, unknown>;
  if (typeof d.id !== 'string' || !UUID_RE.test(d.id)) errors.push({field:'id', message:'Must be valid UUID'});
  if (typeof d.email !== 'string' || !EMAIL_RE.test(d.email)) errors.push({field:'email', message:'Must be valid email'});
  if (typeof d.name !== 'string' || d.name.length < 1 || d.name.length > 100) errors.push({field:'name', message:'Must be 1-100 chars'});
  if (typeof d.role !== 'string' || !ROLES.has(d.role)) errors.push({field:'role', message:'Must be admin/editor/viewer'});
  return { valid: errors.length === 0, errors };
}
