import json
from typing import Generator, Callable

def filtered_jsonl_reader(
    filepath: str,
    predicate: Callable[[dict], bool]
) -> Generator[dict, None, None]:
    with open(filepath, 'r', encoding='utf-8') as f:
        for line_num, line in enumerate(f, 1):
            line = line.strip()
            if not line:
                continue
            try:
                record = json.loads(line)
            except json.JSONDecodeError:
                continue  # Skip malformed lines
            if predicate(record):
                yield record

# Usage — process a 10GB JSONL file with constant memory
high_value = filtered_jsonl_reader(
    'transactions.jsonl',
    lambda r: r.get('amount', 0) > 10000
)

for record in high_value:
    print(f"{record['id']}: {record['amount']}")

# Chain generators for pipeline processing
def enrich(records):
    for r in records:
        r['risk_flag'] = r['amount'] > 50000
        yield r

for record in enrich(high_value):
    process(record)
```

Generators use O(1) memory regardless of file size — each line is read, processed, and discarded. The `predicate` parameter makes it reusable for any filter. Chain multiple generators for ETL pipelines.

